#!/usr/bin/env node
/**
 * Writes website/src/generated/integrateActivationShellStatic.ts from scripts/templates/integrate-activation-shell.bash.
 * Usage: node scripts/generate-integrate-activation-shell.mjs [--check]
 * Default: write. --check exits 1 if the generated file would change.
 */
import { readFileSync, writeFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.resolve(__dirname, "..");
const templatePath = path.join(root, "scripts", "templates", "integrate-activation-shell.bash");
const outPath = path.join(root, "website", "src", "generated", "integrateActivationShellStatic.ts");

const bash = readFileSync(templatePath, "utf8").replace(/\r\n/g, "\n");
if (!bash.endsWith("\n")) {
  console.error("generate-integrate-activation-shell: template must end with newline");
  process.exit(1);
}

const escaped = bash.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/\$\{/g, "\\${");

const ts = `/* Generated by scripts/generate-integrate-activation-shell.mjs — do not edit by hand. */
export const INTEGRATE_ACTIVATION_SHELL_BODY = \`${escaped}\`;
`;

const check = process.argv.includes("--check");
if (check) {
  let existing;
  try {
    existing = readFileSync(outPath, "utf8");
  } catch {
    console.error("generate-integrate-activation-shell: missing output file for --check");
    process.exit(1);
  }
  if (existing !== ts) {
    console.error("generate-integrate-activation-shell: committed file is stale; run generator without --check");
    process.exit(1);
  }
  process.exit(0);
}

writeFileSync(outPath, ts, "utf8");
